8	pub fn gen_expr(expr: &Expr, state: &mut CodegenState) {
9	    match expr {
10	        Expr::IntLit(val) => tc24r_expr_literal::gen_int_lit(state, *val),
11	        Expr::StringLit(s) => tc24r_expr_literal::gen_string_lit(state, s),
12	        Expr::Ident(name) => tc24r_expr_variable::gen_ident(state, name),
13	        Expr::Assign { name, value } => {
14	            tc24r_expr_variable::gen_assign(state, name, value, gen_expr)
15	        }
16	        Expr::Call { name, args } => tc24r_expr_call::gen_call(state, name, args, gen_expr),
17	        Expr::UnaryOp { op, operand } => {
18	            tc24r_expr_ops::gen_unary_dispatch(state, *op, operand, gen_expr)
19	        }
20	        Expr::BinOp { op, lhs, rhs } => {
21	            tc24r_expr_ops::gen_binop_dispatch(state, *op, lhs, rhs, gen_expr)
22	        }
23	        Expr::AddrOf(name) => tc24r_expr_variable::gen_addr_of(state, name),
24	        Expr::Deref(ptr) => tc24r_expr_pointer::gen_deref(state, ptr, gen_expr),
25	        Expr::Cast { expr: inner, .. } => gen_expr(inner, state),
26	        Expr::DerefAssign { ptr, value } => {
27	            tc24r_expr_pointer::gen_deref_assign(state, ptr, value, gen_expr)
28	        }
29	        Expr::PreInc(name) | Expr::PreDec(name) | Expr::PostInc(name) | Expr::PostDec(name) => {
30	            let delta = match expr {
31	                Expr::PreInc(_) | Expr::PostInc(_) => 1,
32	                _ => -1,
33	            };
34	            let post = matches!(expr, Expr::PostInc(_) | Expr::PostDec(_));
35	            tc24r_ops_incdec::gen_inc_dec(state, name, delta, post);
36	        }
37	        Expr::StmtExpr(block) => {
38	            for s in &block.stmts {
39	                gen_stmt(s, state);
40	            }
41	        }
42	        Expr::MemberAccess { object, member } => {
43	            tc24r_expr_struct::gen_member_access(state, object, member, gen_expr)
44	        }
45	        Expr::MemberAssign {
46	            object,
47	            member,
48	            value,
49	        } => tc24r_expr_struct::gen_member_assign(state, object, member, value, gen_expr),
50	        Expr::IndirectCall { callee, args } => {
51	            tc24r_expr_call::gen_indirect_call(state, callee, args, gen_expr)
52	        }
53	        Expr::Ternary {
54	            cond,
55	            then_expr,
56	            else_expr,
