use tc24r_ast::Expr;
use tc24r_codegen_state::CodegenState;
use tc24r_emit_core::{emit_bra, emit_brt, new_label};
use tc24r_emit_macros::emit;

use crate::gen_stmt::gen_stmt;

pub fn gen_expr(expr: &Expr, state: &mut CodegenState) {
    match expr {
        Expr::IntLit(val) => tc24r_expr_literal::gen_int_lit(state, *val),
        Expr::StringLit(s) => tc24r_expr_literal::gen_string_lit(state, s),
        Expr::Ident(name) => tc24r_expr_variable::gen_ident(state, name),
        Expr::Assign { name, value } => {
            tc24r_expr_variable::gen_assign(state, name, value, gen_expr)
        }
        Expr::Call { name, args } => tc24r_expr_call::gen_call(state, name, args, gen_expr),
        Expr::UnaryOp { op, operand } => {
            tc24r_expr_ops::gen_unary_dispatch(state, *op, operand, gen_expr)
        }
        Expr::BinOp { op, lhs, rhs } => {
            tc24r_expr_ops::gen_binop_dispatch(state, *op, lhs, rhs, gen_expr)
        }
        Expr::AddrOf(name) => tc24r_expr_variable::gen_addr_of(state, name),
        Expr::Deref(ptr) => tc24r_expr_pointer::gen_deref(state, ptr, gen_expr),
        Expr::Cast { expr: inner, .. } => gen_expr(inner, state),
        Expr::DerefAssign { ptr, value } => {
            tc24r_expr_pointer::gen_deref_assign(state, ptr, value, gen_expr)
        }
        Expr::PreInc(name) | Expr::PreDec(name) | Expr::PostInc(name) | Expr::PostDec(name) => {
            let delta = match expr {
                Expr::PreInc(_) | Expr::PostInc(_) => 1,
                _ => -1,
            };
            let post = matches!(expr, Expr::PostInc(_) | Expr::PostDec(_));
            tc24r_ops_incdec::gen_inc_dec(state, name, delta, post);
        }
        Expr::StmtExpr(block) => {
            for s in &block.stmts {
                gen_stmt(s, state);
            }
        }
        Expr::MemberAccess { object, member } => {
            tc24r_expr_struct::gen_member_access(state, object, member, gen_expr)
        }
        Expr::MemberAssign {
            object,
            member,
            value,
        } => tc24r_expr_struct::gen_member_assign(state, object, member, value, gen_expr),
        Expr::IndirectCall { callee, args } => {
            tc24r_expr_call::gen_indirect_call(state, callee, args, gen_expr)
        }
        Expr::Ternary {
            cond,
            then_expr,
            else_expr,
        } => gen_ternary(state, cond, then_expr, else_expr),
    }
}

fn gen_ternary(state: &mut CodegenState, cond: &Expr, then_expr: &Expr, else_expr: &Expr) {
    let else_label = new_label(state);
    let done_label = new_label(state);

    gen_expr(cond, state);
    emit!(state, "        ceq     r0,z");
    emit_brt(state, &else_label);
    gen_expr(then_expr, state);
    emit_bra(state, &done_label);
    emit!(state, "{else_label}:");
    gen_expr(else_expr, state);
    emit!(state, "{done_label}:");
}

#!/usr/bin/env bash
# Run a single chibicc test through tc24r -> cor24-run pipeline.
#
# Usage: scripts/run-chibicc-test.sh <test-name>
#   e.g.: scripts/run-chibicc-test.sh arith
#
# Reads test from ~/github/softwarewrighter/chibicc/test/<name>.c
# Copies to temp, compiles with tc24r, runs with cor24-run.
# Exit 0 if r0=0 (all assertions pass), exit 1 otherwise.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
ROOT_DIR="$(dirname "$SCRIPT_DIR")"
CC24="$ROOT_DIR/components/cli/target/release/tc24r"
INCLUDE_DIR="$ROOT_DIR/include"
CHIBICC_TEST="${HOME}/github/softwarewrighter/chibicc/test"

if [ $# -lt 1 ]; then
    echo "usage: $0 <test-name>"
    exit 1
fi

NAME="$1"
SRC="$CHIBICC_TEST/$NAME.c"

if [ ! -f "$SRC" ]; then
    echo "SKIP: $SRC not found"
    exit 2
fi

# Always rebuild to avoid stale binary issues (cargo is incremental)
cargo build --manifest-path "$ROOT_DIR/components/cli/Cargo.toml" --release --quiet

TMPDIR=$(mktemp -d)
trap 'rm -rf "$TMPDIR"' EXIT

# Adapt the test file for tc24r freestanding:
# - Strip lines with printf/sprintf/exit/float/double/long/hosted decls
# - Strip binary and octal literals our lexer doesn't handle
# - Our include/test.h provides a freestanding ASSERT
# Using awk (portable across GNU/BSD) instead of sed.
awk '
/printf/   { next }
/sprintf/  { next }
/vsprintf/ { next }
/exit\(/   { next }
/^void assert/ { next }
/^int ext/  { next }
/^int \*ext/ { next }
/^int common_/ { next }
/^static int common_/ { next }
/^int false_fn/ { next }
/^int true_fn/ { next }
/^int char_fn/ { next }
/^int short_fn/ { next }
/^int uchar_fn/ { next }
/^int ushort_fn/ { next }
/^static int static_fn/ { next }
/^int ext_fn/ { next }
/float/    { next }
/double/   { next }
/long/     { next }
/short/    { next }
/_Bool/    { next }
/0b[01]/   { next }
/0[0-7][0-7]/ { next }
/assert.*size/ { next }
{ print }
' "$SRC" > "$TMPDIR/$NAME.c"

# Copy our freestanding test.h into the temp dir so it takes precedence
# over chibicc's test.h (quoted includes check source_dir first)
cp "$INCLUDE_DIR/test.h" "$TMPDIR/test.h"

# Compile
if ! "$CC24" "$TMPDIR/$NAME.c" -o "$TMPDIR/$NAME.s" -I "$INCLUDE_DIR" -I "$CHIBICC_TEST" 2>"$TMPDIR/tc24r.err"; then
    echo "COMPILE_FAIL: $NAME -- $(head -1 "$TMPDIR/tc24r.err")"
    exit 1
fi

# Assemble and run
OUTPUT=$(cor24-run --run "$TMPDIR/$NAME.s" --dump --speed 0 --time 10 2>&1)
R0=$(echo "$OUTPUT" | grep "r0:" | head -1 | awk -F'[()]' '{print $2}' | tr -d ' ')
HALTED=$(echo "$OUTPUT" | grep "Halted:" | head -1 | awk '{print $2}')

if [ "$HALTED" != "true" ]; then
    echo "TIMEOUT: $NAME (did not halt)"
    exit 1
fi

if [ "$R0" = "0" ]; then
    echo "PASS: $NAME (r0=0)"
    exit 0
else
    echo "FAIL: $NAME (r0=$R0)"
    exit 1
fi

