1	//! Type parsing: consume tokens and produce a Type AST node.
2	
3	use tc24r_ast::Type;
4	use tc24r_error::CompileError;
5	use tc24r_parse_stream::TokenStream;
6	use tc24r_token::TokenKind;
7	
8	/// Consume and discard storage-class / type-qualifier keywords.
9	/// Returns `true` if at least one qualifier was consumed.
10	fn consume_qualifiers(ts: &mut TokenStream) -> bool {
11	    let mut had = false;
12	    while matches!(
13	        ts.peek().kind,
14	        TokenKind::Static | TokenKind::Extern | TokenKind::Const | TokenKind::Inline
15	    ) {
16	        ts.advance();
17	        had = true;
18	    }
19	    had
20	}
21	
22	/// Parse a base type keyword (char/int/void/enum/struct/typedef alias).
23	fn parse_base_type(ts: &mut TokenStream, had_qualifier: bool) -> Result<Type, CompileError> {
24	    // Consume type modifiers: long, short, signed, unsigned
25	    // On COR24, all integer types are 24-bit; long/short are accepted and treated as int.
26	    let mut had_modifier = false;
27	    let mut is_unsigned = false;
28	    while matches!(
29	        ts.peek().kind,
30	        TokenKind::Long | TokenKind::Short | TokenKind::Signed | TokenKind::Unsigned
31	    ) {
32	        if ts.peek().kind == TokenKind::Unsigned {
33	            is_unsigned = true;
34	        }
35	        ts.advance();
36	        had_modifier = true;
37	    }
38	
39	    match ts.peek().kind {
40	        TokenKind::Char => {
41	            ts.advance();
42	            Ok(Type::Char)
43	        }
44	        TokenKind::Int => {
45	            ts.advance();
46	            if is_unsigned { Ok(Type::UnsignedInt) } else { Ok(Type::Int) }
47	        }
48	        _ if had_modifier => {
49	            if is_unsigned { Ok(Type::UnsignedInt) } else { Ok(Type::Int) }
50	        }
51	        TokenKind::Void => {
52	            ts.advance();
53	            Ok(Type::Void)
54	        }
55	        TokenKind::Enum => {
56	            ts.advance();
57	            if matches!(ts.peek().kind, TokenKind::Ident(_)) {
58	                ts.advance();
59	            }
60	            Ok(Type::Int)
61	        }
62	        TokenKind::Struct => {
63	            ts.advance();
64	            tc24r_parser_struct::parse_struct_type(ts, parse_type, false)
65	        }
66	        TokenKind::Union => {
67	            ts.advance();
68	            tc24r_parser_struct::parse_struct_type(ts, parse_type, true)
69	        }
70	        TokenKind::Ident(ref name) if ts.type_aliases.contains_key(name) => {
71	            let resolved = ts.type_aliases[name].clone();
72	            ts.advance();
73	            Ok(resolved)
74	        }
75	        _ if had_qualifier => Ok(Type::Int),
76	        _ => Err(CompileError::new(
77	            format!("expected type, got {:?}", ts.peek().kind),
78	            Some(ts.current_span()),
79	        )),
80	    }
81	}
82	
83	/// Consume pointer stars and trailing const qualifiers after a base type.
84	fn consume_pointers(ts: &mut TokenStream, base: Type) -> Type {
85	    while ts.eat(TokenKind::Const) {}
86	    let mut ty = base;
87	    while ts.eat(TokenKind::Star) {
88	        while ts.eat(TokenKind::Const) {}
89	        ty = Type::Ptr(Box::new(ty));
90	    }
91	    ty
92	}
93	
94	pub fn parse_type(ts: &mut TokenStream) -> Result<Type, CompileError> {
95	    let had_qualifier = consume_qualifiers(ts);
96	    let base = parse_base_type(ts, had_qualifier)?;
97	    Ok(consume_pointers(ts, base))
98	}
99

