        TokenKind::Char => {
            ts.advance();
            Ok(Type::Char)
        }
        TokenKind::Int => {
            ts.advance();
            if is_unsigned { Ok(Type::UnsignedInt) } else { Ok(Type::Int) }
        }
        _ if had_modifier => {
            if is_unsigned { Ok(Type::UnsignedInt) } else { Ok(Type::Int) }
        }
        TokenKind::Void => {
            ts.advance();
            Ok(Type::Void)
        }
        TokenKind::Enum => {
            ts.advance();
            if matches!(ts.peek().kind, TokenKind::Ident(_)) {
                ts.advance();
            }
            Ok(Type::Int)
