        TokenKind::Struct => {
            ts.advance();
            tc24r_parser_struct::parse_struct_type(ts, parse_type, false)
        }
        TokenKind::Union => {
            ts.advance();
            tc24r_parser_struct::parse_struct_type(ts, parse_type, true)
        }
