1	//! Pointer dereference (read and write).
2	
3	use tc24r_ast::{Expr, Type};
4	use tc24r_codegen_state::CodegenState;
5	use tc24r_emit_macros::emit;
6	use tc24r_type_infer::{expr_type, is_simple_expr};
7	
8	/// Callback type for recursive expression generation.
9	pub type GenExprFn = fn(&Expr, &mut CodegenState);
10	
11	/// Dereference a pointer: evaluate `ptr`, load the value it points to into r0.
12	pub fn gen_deref(state: &mut CodegenState, ptr: &Expr, gen_expr_fn: GenExprFn) {
13	    let is_byte = is_char_ptr(state, ptr);
14	    gen_expr_fn(ptr, state);
15	    if is_byte {
16	        emit!(state, "        lbu     r0,0(r0)");
17	    } else {
18	        emit!(state, "        lw      r0,0(r0)");
19	    }
20	}
21	
22	/// Assign through a pointer: evaluate `value`, evaluate `ptr`, store.
23	///
24	/// When value is a simple expression, evaluates ptr first then loads
25	/// value directly into r0, skipping push/pop.
26	pub fn gen_deref_assign(
27	    state: &mut CodegenState,
28	    ptr: &Expr,
29	    value: &Expr,
30	    gen_expr_fn: GenExprFn,
31	) {
32	    let is_byte = is_char_ptr(state, ptr);
33	    if is_simple_expr(value, state) && !is_global_var(value, state) {
34	        // Safe to skip push/pop: value loads into r0 without clobbering r1.
35	        // Globals are excluded because loading them uses r1 as scratch
36	        // (la r1,_name; lw r0,0(r1)), which would clobber the ptr in r1.
37	        gen_expr_fn(ptr, state);
38	        emit!(state, "        mov     r1,r0");
39	        gen_expr_fn(value, state);
40	    } else {
41	        gen_expr_fn(value, state);
42	        emit!(state, "        push    r0");
43	        gen_expr_fn(ptr, state);
