            .map(|b| b.to_string())
            .collect();
        let byte_str = bytes.join(",");
        emit!(state, "        .byte   {byte_str}");
    }
}

//! Variable assignment (store).

use tc24r_ast::{Expr, Type};
use tc24r_codegen_state::CodegenState;
use tc24r_emit_load_store::gen_store_by_name;
use tc24r_emit_macros::emit;

/// Callback type for recursive expression generation.
pub type GenExprFn = fn(&Expr, &mut CodegenState);

/// Evaluate `value` and store the result into variable `name`.
pub fn gen_assign(state: &mut CodegenState, name: &str, value: &Expr, gen_expr_fn: GenExprFn) {
    gen_expr_fn(value, state);
    if state.globals.contains(name) {
        let is_char = state.global_types.get(name) == Some(&Type::Char);
        emit!(state, "        la      r1,_{name}");
        if is_char {
            emit!(state, "        sb      r0,0(r1)");
        } else {
            emit!(state, "        sw      r0,0(r1)");
        }
    } else {
        gen_store_by_name(state, name);
    }
}

//! Variable load with array decay.

use tc24r_ast::Type;
use tc24r_codegen_state::CodegenState;
use tc24r_emit_load_store::{gen_addr_of, gen_load_by_name};
use tc24r_emit_macros::emit;

/// Load a variable into r0. Arrays decay to a pointer (address of first element).
/// Function names used as values produce their code address (for function pointers).
pub fn gen_ident(state: &mut CodegenState, name: &str) {
    // Array decay: local or global arrays produce their address, not a load
    if matches!(state.local_types.get(name), Some(Type::Array(..)))
        || matches!(state.global_types.get(name), Some(Type::Array(..)))
    {
        gen_addr_of(state, name);
        return;
    }
    if state.globals.contains(name) {
        let is_char = state.global_types.get(name) == Some(&Type::Char);
        emit!(state, "        la      r1,_{name}");
        if is_char {
            emit!(state, "        lbu     r0,0(r1)");
        } else {
            emit!(state, "        lw      r0,0(r1)");
        }
    } else if state.locals.contains_key(name) {
        gen_load_by_name(state, name);
    } else if state.function_types.contains_key(name) {
        // Function name used as value: load its code address
        emit!(state, "        la      r0,_{name}");
    } else {
        gen_load_by_name(state, name);
    }
}

//! Pointer dereference (read and write).

use tc24r_ast::{Expr, Type};
use tc24r_codegen_state::CodegenState;
use tc24r_emit_macros::emit;
use tc24r_type_infer::{expr_type, is_simple_expr};

/// Callback type for recursive expression generation.
pub type GenExprFn = fn(&Expr, &mut CodegenState);

/// Dereference a pointer: evaluate `ptr`, load the value it points to into r0.
pub fn gen_deref(state: &mut CodegenState, ptr: &Expr, gen_expr_fn: GenExprFn) {
    let is_byte = is_char_ptr(state, ptr);
    gen_expr_fn(ptr, state);
    if is_byte {
        emit!(state, "        lbu     r0,0(r0)");
    } else {
        emit!(state, "        lw      r0,0(r0)");
    }
}

/// Assign through a pointer: evaluate `value`, evaluate `ptr`, store.
///
/// When value is a simple expression, evaluates ptr first then loads
/// value directly into r0, skipping push/pop.
pub fn gen_deref_assign(
    state: &mut CodegenState,
    ptr: &Expr,
    value: &Expr,
    gen_expr_fn: GenExprFn,
) {
    let is_byte = is_char_ptr(state, ptr);
    if is_simple_expr(value, state) && !is_global_var(value, state) {
        // Safe to skip push/pop: value loads into r0 without clobbering r1.
        // Globals are excluded because loading them uses r1 as scratch
        // (la r1,_name; lw r0,0(r1)), which would clobber the ptr in r1.
        gen_expr_fn(ptr, state);
        emit!(state, "        mov     r1,r0");
        gen_expr_fn(value, state);
    } else {
        gen_expr_fn(value, state);
        emit!(state, "        push    r0");
        gen_expr_fn(ptr, state);
        emit!(state, "        mov     r1,r0");
        emit!(state, "        pop     r0");
    }
    if is_byte {
        emit!(state, "        sb      r0,0(r1)");
    } else {
        emit!(state, "        sw      r0,0(r1)");
    }
}

/// Check whether `expr` is a global variable reference.
fn is_global_var(expr: &Expr, state: &CodegenState) -> bool {
    if let Expr::Ident(name) = expr {
        state.globals.contains(name)
    } else {
        false
    }
}

/// Check whether `ptr` is a char pointer.
fn is_char_ptr(state: &CodegenState, ptr: &Expr) -> bool {
    matches!(
        expr_type(state, ptr),
        Some(Type::Ptr(inner)) if *inner == Type::Char
    )
}

//! Struct member access and assignment.

use tc24r_ast::{BinOp, Expr, Type};
use tc24r_codegen_state::CodegenState;
use tc24r_emit_core::load_immediate;
use tc24r_emit_macros::emit;

/// Callback type for recursive expression generation.
pub type GenExprFn = fn(&Expr, &mut CodegenState);

/// Load struct member `object.member` into r0.
pub fn gen_member_access(
    state: &mut CodegenState,
    object: &Expr,
    member: &str,
    gen_expr_fn: GenExprFn,
) {
    let (mem_offset, is_char) = member_info(state, object, member);
    emit_member_addr(state, object, mem_offset, gen_expr_fn);
    if is_char {
        emit!(state, "        lbu     r0,0(r0)");
    } else {
        emit!(state, "        lw      r0,0(r0)");
    }
}

/// Store value into struct member `object.member`.
pub fn gen_member_assign(
    state: &mut CodegenState,
    object: &Expr,
    member: &str,
    value: &Expr,
    gen_expr_fn: GenExprFn,
) {
    let (mem_offset, is_char) = member_info(state, object, member);
    gen_expr_fn(value, state);
    emit!(state, "        push    r0");
    emit_member_addr(state, object, mem_offset, gen_expr_fn);
    emit!(state, "        mov     r1,r0");
    emit!(state, "        pop     r0");
    if is_char {
        emit!(state, "        sb      r0,0(r1)");
    } else {
        emit!(state, "        sw      r0,0(r1)");
    }
}

/// Emit code to compute member address into r0.
fn emit_member_addr(
    state: &mut CodegenState,
    object: &Expr,
    mem_offset: i32,
    gen_expr_fn: GenExprFn,
) {
    match object {
        Expr::Ident(name) => {
            // Local struct: fp + var_offset + member_offset
            let fp_offset = state.locals[name.as_str()];
            load_immediate(state, fp_offset + mem_offset);
            emit!(state, "        add     r0,fp");
        }
        Expr::Deref(ptr) => {
            // Pointer to struct: evaluate ptr, add member_offset
            gen_expr_fn(ptr, state);
            if mem_offset != 0 {
                emit!(state, "        push    r0");
                load_immediate(state, mem_offset);
                emit!(state, "        pop     r1");
                emit!(state, "        add     r0,r1");
            }
        }
        _ => {
            // General case: evaluate object as address, add offset
            gen_expr_fn(object, state);
            if mem_offset != 0 {
                emit!(state, "        push    r0");
                load_immediate(state, mem_offset);
                emit!(state, "        pop     r1");
                emit!(state, "        add     r0,r1");
            }
        }
    }
}

/// Get member offset and whether it's a char type.
fn member_info(state: &CodegenState, object: &Expr, member: &str) -> (i32, bool) {
    let ty = object_type(state, object);
    let m = ty.find_member(member).unwrap_or_else(|| {
        panic!("unknown struct member '{member}' in type {ty:?}")
    });
    (m.offset, m.ty == Type::Char)
}

/// Determine the struct type of the object expression.
/// Walks the expression tree to resolve nested member accesses.
fn object_type(state: &CodegenState, object: &Expr) -> Type {
    let ty = match object {
        Expr::Ident(name) => {
            if let Some(ty) = state.local_types.get(name.as_str()) {
                ty.clone()
            } else if let Some(ty) = state.global_types.get(name.as_str()) {
                ty.clone()
            } else {
                Type::Int
            }
        }
        Expr::Deref(ptr) => {
            let ptr_ty = object_type(state, ptr);
            match ptr_ty {
                Type::Ptr(inner) => *inner,
                _ => ptr_ty,
            }
        }
        Expr::Call { name, .. } => {
            if let Some(ty) = state.function_types.get(name.as_str()) {
                ty.clone()
            } else {
                Type::Int
            }
        }
        Expr::MemberAccess { object: obj, member } => {
            let struct_ty = object_type(state, obj);
            if let Some(m) = struct_ty.find_member(member) {
                m.ty.clone()
            } else {
                Type::Int
            }
        }
        Expr::BinOp { op: BinOp::Add, lhs, .. }
        | Expr::BinOp { op: BinOp::Sub, lhs, .. } => {
            // Pointer arithmetic preserves pointer type (e.g. arr + i)
            let lhs_ty = object_type(state, lhs);
            match lhs_ty {
                Type::Ptr(_) => lhs_ty,
                Type::Array(inner, _) => Type::Ptr(inner), // array decay
                _ => Type::Int,
            }
        }
        _ => Type::Int,
    };
    // Resolve incomplete struct placeholders via the struct registry
    resolve_struct(state, ty)
}

/// If a struct type is an empty placeholder (forward-declared),
/// look up the full definition from the struct registry.
fn resolve_struct(state: &CodegenState, ty: Type) -> Type {
    match &ty {
        Type::Struct { tag: Some(name), members, .. } if members.is_empty() => {
            if let Some(full) = state.struct_types.get(name) {
                full.clone()
            } else {
                ty
            }
        }
        Type::Ptr(inner) => Type::Ptr(Box::new(resolve_struct(state, *inner.clone()))),
        _ => ty,
    }
}

